mapper.update:
UPDATE STOCOGCM SET
      MOD_USER_ID = #{ses.userId}
    , DEL_FLAG = '0'
    , BUYER_NM = #{buyerNm}
    , BUYER_NM_ENG = #{buyerNmEng}
    , LANG_CD = #{langCd}
    , COUNTRY_CD = #{countryCd}
    , CITY_NM = #{cityNm}
    , ADDR = GETENCPERSONALINFO(#{address})
    , ADDR_ENG = GETENCPERSONALINFO(#{addressEng})
    , ZIP_CD = GETENCPERSONALINFO(#{zipCd})
    , TEL_NUM = GETENCPERSONALINFO(#{telNum})
    , IRS_NUM = #{irsNum}
    , FAX_NUM = GETENCPERSONALINFO(#{faxNum})
    , CEO_USER_NM = GETENCPERSONALINFO(#{ceoUserNm})
    , CEO_USER_NM_ENG = GETENCPERSONALINFO(#{ceoUserNmEng})
    , BUSINESS_TYPE = #{businessType}
    , INDUSTRY_TYPE = #{industryType}
    , CUR = #{cur}
    , COMPANY_REG_NUM = #{companyRegNum}
    , DUNS_NUM = #{dunsNum}
    , GMT_CD = #{gmtCd}
    , ACCOUNT_UNIT_CD = #{ACCOUNT_UNIT_CD}
    , ZIP_CD_5 = GETENCPERSONALINFO(#{ZIP_CD_5})
    , USE_FLAG = CASE WHEN (#{USE_FLAG}, '') = '' THEN '0' ELSE '1' END
    , GW_USE_FLAG = CASE WHEN (#{GW_USE_FLAG}, '') = '' THEN '0' ELSE '1' END
    , MOD_DATE = SYSDATE
    , FOUNDATION_DATE = (#{foundationDate}, 'yyyy-MM-dd')
    , IRS_SUB_ZIP_CD = GETENCPERSONALINFO(#{IRS_SUB_ZIP_CD})
    , IRS_SUB_NO = #{IRS_SUB_NO}
    , IRS_SUB_ADDR = GETENCPERSONALINFO(#{IRS_SUB_ADDR})
    , IRS_SUB_NM = #{IRS_SUB_NM}
    , SUB_ZIP_CD_5 = GETENCPERSONALINFO(#{SUB_ZIP_CD_5})
WHERE  GATE_CD = #{gateCd}
AND  BUYER_CD = #{buyerCd}

UPDATE STOCOGCM SET
      DEL_FLAG = '1'
    , MOD_USER_ID = #{ses.userId}
    , MOD_DATE = SYSDATE
 WHERE GATE_CD = #{GATE_CD_ORI}
   AND BUYER_CD = #{BUYER_CD_ORI}
